// Determine call type and prepare for processing
const inputData = items[0].json;

// Accept data from webhook or manual trigger
const transcript = inputData.transcript || '';
const callType = inputData.call_type || 'demo';  // 'demo' or 'onboarding'
const fileName = inputData.file_name || 'unknown';
const accountId = inputData.account_id || '';

// Auto-detect call type if not specified
let detectedType = callType;
if (callType === 'auto') {
  const lower = transcript.toLowerCase();
  const onboardingSignals = ['onboarding', 'business hours are', 'our hours are', 'emergency means', 'after hours', 'servicetrade'];
  const demoSignals = ['demo', 'show you', 'how clara works', 'interested in', 'pain point'];

  const obScore = onboardingSignals.filter(s => lower.includes(s)).length;
  const demoScore = demoSignals.filter(s => lower.includes(s)).length;
  detectedType = obScore > demoScore ? 'onboarding' : 'demo';
}

return [{
  json: {
    transcript: transcript,
    call_type: detectedType,
    file_name: fileName,
    account_id: accountId,
    timestamp: new Date().toISOString()
  }
}];

// Pipeline A: Extract account memo from demo call transcript
const transcript = $json.transcript;
const fileName = $json.file_name;

// Rule-based extraction (zero-cost, no LLM needed)
function extractCompanyName(text) {
  const patterns = [
    /(?:company|business|we are|this is|i'm with|we're)\s+(?:called\s+)?([A-Z][A-Za-z\s&']+(?:LLC|Inc|Corp|Co|Services|Solutions|Electric|Plumbing|HVAC|Fire|Protection|Mechanical|Sprinkler)?)/gi,
    /([A-Z][A-Za-z]+(?:\s+[A-Z][A-Za-z]+){0,3})\s+(?:fire protection|electric|plumbing|hvac|mechanical|sprinkler|services)/gi
  ];
  for (const pattern of patterns) {
    const match = pattern.exec(text);
    if (match && match[1] && match[1].length > 3) return match[1].trim();
  }
  return fileName.replace(/[_-]/g, ' ').replace(/\.[^.]+$/, '');
}

function extractBusinessHours(text) {
  const hourPattern = /(\d{1,2}(?::\d{2})?\s*(?:am|pm))\s*(?:to|until|-)\s*(\d{1,2}(?::\d{2})?\s*(?:am|pm))/gi;
  const match = hourPattern.exec(text);
  const dayPattern = /(Monday\s*(?:through|to|-)\s*(?:Friday|Saturday|Sunday))/gi;
  const dayMatch = dayPattern.exec(text);
  const tzPattern = /(Eastern|Central|Mountain|Pacific|EST|CST|MST|PST)/gi;
  const tzMatch = tzPattern.exec(text);
  return {
    days: dayMatch ? dayMatch[1] : '',
    start: match ? match[1] : '',
    end: match ? match[2] : '',
    timezone: tzMatch ? tzMatch[1] : ''
  };
}

function extractServices(text) {
  const services = [];
  const keywords = {
    'fire protection': 'Fire Protection',
    'fire alarm': 'Fire Alarm Systems',
    'fire sprinkler': 'Fire Sprinkler Systems',
    'fire extinguisher': 'Fire Extinguisher Service',
    'inspection': 'Inspection Services',
    'maintenance': 'Maintenance',
    'emergency service': 'Emergency Service',
    'monitoring': 'Alarm Monitoring',
    'electrical': 'Electrical Services',
    'hvac': 'HVAC Services',
    'plumbing': 'Plumbing Services',
    'pressure washing': 'Pressure Washing'
  };
  const lower = text.toLowerCase();
  for (const [kw, svc] of Object.entries(keywords)) {
    if (lower.includes(kw)) services.push(svc);
  }
  return services;
}

function generateAccountId(name) {
  const normalized = name.toLowerCase().replace(/\s+/g, '_').replace(/[^a-z0-9_]/g, '').substring(0, 20);
  let hash = 0;
  for (let i = 0; i < name.length; i++) {
    hash = ((hash << 5) - hash) + name.charCodeAt(i);
    hash = hash & hash;
  }
  return `acct_${normalized}_${Math.abs(hash).toString(16).substring(0, 8)}`;
}

const companyName = extractCompanyName(transcript);
const accountId = $json.account_id || generateAccountId(companyName);
const hours = extractBusinessHours(transcript);
const services = extractServices(transcript);

const unknowns = [];
if (!hours.start) unknowns.push('Business hours not explicitly stated in demo call');
if (!hours.timezone) unknowns.push('Timezone not specified');

const memo = {
  account_id: accountId,
  company_name: companyName,
  business_type: 'service business',
  business_hours: hours,
  office_address: '',
  services_supported: services,
  emergency_definition: [],
  emergency_routing_rules: { who_to_call: [], call_order: [], fallback: '' },
  non_emergency_routing_rules: { during_hours: 'Transfer to office', after_hours: 'Collect information and confirm follow-up' },
  call_transfer_rules: { timeout_seconds: 30, max_retries: 2, failure_message: 'I apologize, I\'m unable to transfer you right now. Let me take your information.' },
  integration_constraints: [],
  after_hours_flow_summary: 'Standard after-hours flow with emergency detection',
  office_hours_flow_summary: 'Standard business hours flow with transfer',
  questions_or_unknowns: unknowns,
  notes: '',
  source_type: 'demo',
  version: 'v1',
  extraction_method: 'n8n_rule_based'
};

return [{ json: { memo: memo, account_id: accountId, company_name: companyName, call_type: 'demo' } }];

// Pipeline B: Extract onboarding data
const transcript = $json.transcript;
const fileName = $json.file_name;

// Same extraction logic as demo but with onboarding context
function extractCompanyName(text) {
  const patterns = [
    /(?:company|business|we are|this is|i'm with|we're)\s+(?:called\s+)?([A-Z][A-Za-z\s&']+(?:LLC|Inc|Corp|Co|Services|Solutions|Electric|Plumbing|HVAC|Fire|Protection|Mechanical|Sprinkler)?)/gi
  ];
  for (const pattern of patterns) {
    const match = pattern.exec(text);
    if (match && match[1] && match[1].length > 3) return match[1].trim();
  }
  return fileName.replace(/[_-]/g, ' ').replace(/\.[^.]+$/, '');
}

function generateAccountId(name) {
  const normalized = name.toLowerCase().replace(/\s+/g, '_').replace(/[^a-z0-9_]/g, '').substring(0, 20);
  let hash = 0;
  for (let i = 0; i < name.length; i++) {
    hash = ((hash << 5) - hash) + name.charCodeAt(i);
    hash = hash & hash;
  }
  return `acct_${normalized}_${Math.abs(hash).toString(16).substring(0, 8)}`;
}

const companyName = extractCompanyName(transcript);
const accountId = $json.account_id || generateAccountId(companyName);

// Onboarding extracts more detail
const memo = {
  account_id: accountId,
  company_name: companyName,
  source_type: 'onboarding',
  version: 'v2',
  extraction_method: 'n8n_rule_based',
  transcript_excerpt: transcript.substring(0, 500)
};

return [{ json: { onboarding_memo: memo, account_id: accountId, company_name: companyName, call_type: 'onboarding', transcript: transcript } }];

// Generate Retell Agent Spec from Account Memo
const memo = $json.memo;
const company = memo.company_name || 'Unknown Company';
const hours = memo.business_hours || {};
const hoursStr = (hours.start && hours.end) ? `${hours.days || 'Monday-Friday'}, ${hours.start} to ${hours.end} ${hours.timezone || ''}` : 'Not yet configured';

const systemPrompt = `You are Clara, a professional AI receptionist for ${company}.
You handle inbound calls with warmth, efficiency, and professionalism.

Company: ${company}
Business Hours: ${hoursStr}
Services: ${(memo.services_supported || []).join(', ') || 'Various services'}

=== BUSINESS HOURS FLOW ===
1. Greet: "Thank you for calling ${company}. This is Clara, how can I help you today?"
2. Ask purpose of call
3. Collect caller name and callback number
4. Transfer to appropriate party
5. If transfer fails: take message, confirm follow-up
6. "Is there anything else I can help you with?"
7. Close call professionally

=== AFTER-HOURS FLOW ===
1. Greet: "Thank you for calling ${company}. You've reached us after hours."
2. Ask purpose of call
3. Determine if emergency
4. If EMERGENCY: collect name, number, address immediately, attempt transfer
5. If transfer fails: assure callback, log as urgent
6. If NOT emergency: collect details, confirm follow-up next business day
7. "Is there anything else?"
8. Close call

=== RULES ===
- NEVER mention internal tools or functions to the caller
- NEVER fabricate information
- Keep conversations efficient
- Always provide next steps`;

const spec = {
  agent_name: `Clara - ${company}`,
  agent_id: `agent_${memo.account_id}_${memo.version}`,
  version: memo.version || 'v1',
  created_at: new Date().toISOString(),
  account_id: memo.account_id,
  voice_config: {
    voice_style: 'professional_friendly',
    voice_id: 'rachel',
    language: 'en-US'
  },
  system_prompt: systemPrompt,
  key_variables: {
    company_name: company,
    timezone: hours.timezone || '',
    business_hours: hours,
    emergency_contacts: (memo.emergency_routing_rules || {}).who_to_call || []
  },
  call_transfer_protocol: memo.call_transfer_rules || { timeout_seconds: 30, max_retries: 2 },
  fallback_protocol: {
    transfer_failure: 'Collect caller info, log message, assure follow-up',
    system_error: 'Apologize, provide main office number'
  },
  metadata: {
    source_call_type: memo.source_type,
    extraction_method: memo.extraction_method,
    confidence_level: memo.version === 'v1' ? 'preliminary' : 'confirmed'
  }
};

return [{ json: { memo: memo, spec: spec, account_id: memo.account_id, version: memo.version } }];

// Store outputs to local filesystem
const memo = $json.memo;
const spec = $json.spec;
const accountId = $json.account_id;
const version = $json.version || 'v1';

// In n8n, we store the outputs as workflow data
// In production, this would write to filesystem or database
const output = {
  account_id: accountId,
  version: version,
  company_name: memo.company_name,
  stored_at: new Date().toISOString(),
  artifacts: {
    account_memo: memo,
    agent_spec: spec
  },
  storage_path: `outputs/accounts/${accountId}/${version}/`,
  status: 'stored'
};

return [{ json: output }];

// Create task tracker item
const accountId = $json.account_id;
const version = $json.version;
const companyName = $json.company_name;
const unknownsCount = ($json.artifacts.account_memo.questions_or_unknowns || []).length;

const task = {
  task_id: `setup_${accountId}`,
  title: `[${version}] Setup Agent - ${companyName}`,
  status: version === 'v1' ? 'in_progress' : 'review',
  description: `Agent ${version} created for ${companyName}. Open questions: ${unknownsCount}`,
  created_at: new Date().toISOString(),
  metadata: {
    account_id: accountId,
    version: version,
    unknowns_count: unknownsCount
  }
};

return [{ json: { ...($json), task: task } }];

// Merge v1 + onboarding → v2 and generate changelog
const onboardingData = $json;
const accountId = onboardingData.account_id;

// In real n8n, you'd read v1 from storage.
// Here we demonstrate the merge logic.
const changelog = {
  account_id: accountId,
  company_name: onboardingData.company_name,
  from_version: 'v1',
  to_version: 'v2',
  timestamp: new Date().toISOString(),
  changes: [
    { field: 'version', action: 'modified', old_value: 'v1', new_value: 'v2' },
    { field: 'source_type', action: 'modified', old_value: 'demo', new_value: 'onboarding' }
  ],
  summary: 'Onboarding data merged into v1 to produce v2'
};

return [{ json: { account_id: accountId, company_name: onboardingData.company_name, changelog: changelog, call_type: 'onboarding', version: 'v2' } }];
